/**
 * Converts assets/game.html into a TypeScript module that exports the HTML as a string.
 *
 * Run: node scripts/sync-game-html.js
 * Auto-runs before `npm start` and `npx expo start` via the "prestart" script.
 *
 * Edit the game in assets/game.html (real HTML — syntax highlighting, browser debugging).
 * This script generates lib/game-html-content.ts — do NOT edit that file directly.
 */

const fs = require("fs");
const path = require("path");

const htmlPath = path.join(__dirname, "..", "assets", "game.html");
const outPath = path.join(__dirname, "..", "lib", "game-html-content.ts");

const html = fs.readFileSync(htmlPath, "utf-8");

const output = `// AUTO-GENERATED by scripts/sync-game-html.js — do NOT edit this file.
// Edit assets/game.html instead, then run: node scripts/sync-game-html.js
export const GAME_HTML_TEMPLATE = ${JSON.stringify(html)};
`;

fs.writeFileSync(outPath, output, "utf-8");
console.log("[sync-game-html] Generated lib/game-html-content.ts");
